class Solution {
public: 
int solve(vector<int>& nums) {
    int min_price = nums[0];
    int max_profit = 0;
    for (int i = 1; i < nums.size(); i++) {
        if (nums[i] < min_price) min_price = nums[i];
        else max_profit = max(max_profit, nums[i] - min_price);
    }
    return max_profit;
}
};

int main() {
    # Read Input
    int n;
    std::cin >> n;
    std::vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        std::cin >> nums[i];
    }

    # Create Solution Object
    Solution s;

    # Output the result
    std::cout << s.solve(nums) << \n; 
    return 0;
}
